async (page) => {
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);

  // Set attack style to Hack (index 0)
  await page.evaluate(() => window.game.player.setAttackStyle(0));

  // Equip Bronze Axe if in inventory
  const bronzeAxe = parsed.inventory?.find(i => i.key === 'bronzeaxe');
  if (bronzeAxe) {
    await page.evaluate(() => document.getElementById('inventory-button').click());
    await page.waitForTimeout(600);
    await page.evaluate((idx) => {
      const slots = document.querySelectorAll('.item-slot');
      if (slots[idx]) slots[idx].click();
    }, bronzeAxe.slot);
    await page.waitForTimeout(600);
    await page.evaluate(() => { const btn = document.querySelector('.action-equip'); if (btn) btn.click(); });
    await page.waitForTimeout(400);
    await page.evaluate(() => document.getElementById('inventory-button').click());
  }

  return JSON.stringify({pos: parsed.player_position, hasAxeInInventory: !!bronzeAxe});
}

