async (page) => {
  // Set up full incoming packet capture BEFORE talking
  await page.evaluate(() => {
    const ws = window.game?.socket?.connection;
    if (!ws) return;

    window.__allPkts = [];
    // Don't override onmessage this time - use addEventListener
    ws.addEventListener('message', (evt) => {
      try {
        const data = JSON.parse(evt.data);
        window.__allPkts.push(data);
      } catch(e) {}
    });
  });

  // Talk to Blacksmith
  await page.evaluate((id) => window.__talkToNPC(id), '1-15997474');
  await page.waitForTimeout(3000);

  // Get all captured packets
  const pkts = await page.evaluate(() => window.__allPkts || []);

  // Filter for relevant types
  const relevant = pkts.filter(pkt => {
    if (!Array.isArray(pkt)) return false;
    // Each item in pkt is [type, ...data]
    return pkt.some(p => Array.isArray(p) && [23, 31, 17, 44, 28].includes(p[0]));
  }).map(pkt => pkt.filter(p => Array.isArray(p) && [23, 31, 17, 44, 28].includes(p[0])));

  return JSON.stringify({total_pkts: pkts.length, relevant});
}

